   357→  async generateProjections(request: GenerateProjectionsRequest = {}): Promise<LevelingResult> {
   358→    const horizonWeeks = request.horizonWeeks ?? 12;
   359→    const granularity = request.granularity ?? 'WEEKLY';
   360→
   361→    return this.traced(
   362→      'generateProjections',
