   379→          depotIds,
   380→          horizonWeeks,
   381→          granularity
   382→        );
   383→
   384→        // 3. Identify imbalances
   385→        const imbalances = this.identifyImbalances(rawProjections);
   386→        span.setAttribute('overloadedWeeks', imbalances.overloaded.length);
   387→        span.setAttribute('underutilizedWeeks', imbalances.underutilized.length);
   388→
   389→        // 4. Generate adjustments using multiple strategies
