   391→        span.setAttribute('adjustmentCount', adjustments.length);
   392→
   393→        // 5. Apply adjustments to get leveled projections
   394→        const leveledProjections = this.applyAdjustments(rawProjections, adjustments);
   395→
   396→        // 6. Calculate metrics
