   485→
   486→  /**
   487→   * Get adjustments with optional filters
   488→   */
   489→  async getAdjustments(
   490→    filters: AdjustmentFilters,
   491→    page = 1,
   492→    pageSize = 50
   493→  ): Promise<PaginatedResult<ManhourAdjustment>> {
   494→    return this.traced('getAdjustments', async () => {
   495→      const conditions: SQL<unknown>[] = [];
   496→
   497→      if (filters.status) {
