   511→        );
   512→      }
   513→
   514→      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
   515→
   516→      const [adjustments, totalResult] = await Promise.all([
   517→        this.db.query.manhourAdjustments.findMany({
