   520→          limit: pageSize,
   521→          offset: (page - 1) * pageSize,
   522→        }),
   523→        this.db.select({ count: count() }).from(manhourAdjustments).where(whereClause),
   524→      ]);
   525→
   526→      return {
   527→        data: adjustments,
