   530→        pageSize,
   531→      };
   532→    });
   533→  }
   534→
   535→  /**
   536→   * Approve an adjustment
   537→   */
   538→  async approveAdjustment(adjustmentId: string, userId: string): Promise<ManhourAdjustment> {
   539→    return this.inTransaction('approveAdjustment', async (tx, span) => {
   540→      span.setAttribute('adjustmentId', adjustmentId);
   541→      span.setAttribute('userId', userId);
   542→
   543→      // Get adjustment
   544→      const adjustment = await tx.query.manhourAdjustments.findFirst({
