   628→
   629→  /**
   630→   * Get capacity configuration for a depot
   631→   */
   632→  async getCapacity(depotId: string, asOfDate?: Date): Promise<ManhourCapacity | null> {
   633→    return this.traced('getCapacity', async (span) => {
   634→      span.setAttribute('mms.depot.id', depotId);
   635→
   636→      const dateStr = format(asOfDate ?? new Date(), 'yyyy-MM-dd');
   637→
