   712→  /**
   713→   * Check if depot has available labor capacity for additional hours.
   714→   *
   715→   * This method validates that scheduling a PM with the given hours
   716→   * will not exceed the depot's weekly capacity for the target week.
   717→   *
   718→   * @param depotId - Target depot
   719→   * @param targetDate - Date for the PM
   720→   * @param additionalHours - Hours required for the PM
   721→   * @returns Capacity check result with availability status and details
   722→   */
   723→  async checkLaborCapacity(
   724→    depotId: string,
   725→    targetDate: Date | string,
   726→    additionalHours: number
   727→  ): Promise<LaborCapacityResult> {
   728→    return this.traced('checkLaborCapacity', async (span) => {
   729→      span.setAttribute('mms.depot.id', depotId);
   730→      span.setAttribute('mms.manhour.additional_hours', additionalHours);
   731→
   732→      const targetDateObj = typeof targetDate === 'string' ? parseISO(targetDate) : targetDate;
   733→      const weekStart = startOfWeek(targetDateObj, { weekStartsOn: 1 });
   734→      const weekEnd = endOfWeek(weekStart, { weekStartsOn: 1 });
   735→
   736→      span.setAttribute('mms.manhour.week_start', format(weekStart, 'yyyy-MM-dd'));
   737→
   738→      // Get current capacity configuration
   739→      const capacity = await this.getCapacity(depotId, targetDateObj);
   740→      const weeklyCapacity = this.calculateWeeklyCapacity(capacity);
   741→
   742→      // Get currently scheduled hours for the week (PM + overhaul)
   743→      const pmHoursResult = await this.getPmHoursForPeriod(depotId, weekStart, weekEnd);
   744→      const currentScheduledHours = pmHoursResult.pm + pmHoursResult.overhaul;
   745→
   746→      // Calculate totals
   747→      const totalRequiredHours = currentScheduledHours + additionalHours;
   748→      const totalAvailableHours = weeklyCapacity.regular + weeklyCapacity.overtime;
   749→      const utilizationPct = totalAvailableHours > 0 ? totalRequiredHours / totalAvailableHours : 1;
   750→      const remainingCapacity = totalAvailableHours - currentScheduledHours;
   751→      const hasCapacity = additionalHours <= remainingCapacity && utilizationPct <= MAX_UTILIZATION;
   752→
   753→      const result: LaborCapacityResult = {
   754→        hasCapacity,
   755→        depotId,
   756→        weekStart: format(weekStart, 'yyyy-MM-dd'),
   757→        weekEnd: format(weekEnd, 'yyyy-MM-dd'),
   758→        currentScheduledHours,
   759→        additionalHours,
   760→        totalRequiredHours,
   761→        availableHours: {
   762→          regular: weeklyCapacity.regular,
   763→          overtime: weeklyCapacity.overtime,
   764→          total: totalAvailableHours,
   765→        },
   766→        remainingCapacity,
   767→        utilizationPct,
   768→        isOverloaded: utilizationPct > MAX_UTILIZATION,
   769→        message: hasCapacity
   770→          ? `Depot has ${remainingCapacity.toFixed(1)} hours available (${(utilizationPct * 100).toFixed(1)}% utilization after scheduling)`
   771→          : `Depot capacity exceeded: ${totalRequiredHours.toFixed(1)} hours required vs ${totalAvailableHours.toFixed(1)} available (${(utilizationPct * 100).toFixed(1)}% utilization)`,
   772→      };
   773→
   774→      span.setAttribute('mms.manhour.has_capacity', hasCapacity);
   775→      span.setAttribute('mms.manhour.utilization_pct', utilizationPct);
   776→
   777→      if (!hasCapacity) {
   778→        this.log.warn(
   779→          {
   780→            depotId,
   781→            weekStart: result.weekStart,
   782→            currentHours: currentScheduledHours,
   783→            additionalHours,
   784→            totalRequired: totalRequiredHours,
   785→            available: totalAvailableHours,
   786→            utilizationPct,
   787→          },
   788→          'Depot labor capacity exceeded'
   789→        );
   790→      }
   791→
   792→      return result;
   793→    });
   794→  }
