   813→  /**
   814→   * Calculate raw man-hour projections from PM schedule
   815→   */
   816→  private async calculateRawProjections(
   817→    depotIds: string[],
   818→    horizonWeeks: number,
   819→    granularity: 'WEEKLY' | 'MONTHLY'
   820→  ): Promise<ProjectionData[]> {
   821→    const projections: ProjectionData[] = [];
   822→    const now = new Date();
   823→    const startDate = startOfWeek(now, { weekStartsOn: 1 }); // Monday
   824→
   825→    // Get depot info
   826→    const depotList = await this.db.query.depots.findMany({
   827→      where: inArray(depots.id, depotIds),
   828→    });
   829→    const depotMap = new Map(depotList.map((d) => [d.id, d]));
   830→
   831→    for (const depotId of depotIds) {
   832→      const depot = depotMap.get(depotId);
   833→      if (!depot) continue;
   834→
   835→      // Get capacity for depot
   836→      const capacity = await this.getCapacity(depotId);
   837→      const weeklyCapacity = this.calculateWeeklyCapacity(capacity);
   838→
   839→      for (let weekOffset = 0; weekOffset < horizonWeeks; weekOffset++) {
   840→        const weekStart = addWeeks(startDate, weekOffset);
   841→        const weekEnd = endOfWeek(weekStart, { weekStartsOn: 1 });
   842→
   843→        // Get PM, overhaul, and corrective hours for this week
   844→        const [pmResult, correctiveHours] = await Promise.all([
   845→          this.getPmHoursForPeriod(depotId, weekStart, weekEnd),
   846→          this.getCorrectiveHoursForPeriod(depotId, weekStart, weekEnd),
   847→        ]);
   848→
   849→        // Calculate available hours
   850→        const regularHours = weeklyCapacity.regular;
   851→        const overtimeMax =
   852→          regularHours * (capacity ? parseFloat(capacity.maxOvertimePct ?? '20') / 100 : 0.2);
   853→
   854→        const required: RequiredHours = {
   855→          pm: pmResult.pm,
   856→          corrective: correctiveHours,
   857→          overhaul: pmResult.overhaul,
   858→          total: pmResult.pm + pmResult.overhaul + correctiveHours,
   859→        };
   860→
   861→        const available: AvailableHours = {
   862→          regular: regularHours,
   863→          overtime: overtimeMax,
   864→          total: regularHours + overtimeMax,
   865→        };
   866→
   867→        const variance = available.total - required.total;
   868→        const utilizationPct = available.total > 0 ? required.total / available.total : 0;
   869→
   870→        projections.push({
   871→          depotId,
   872→          depotCode: depot.code,
   873→          week: weekStart,
   874→          granularity,
   875→          required,
   876→          available,
   877→          variance,
   878→          utilizationPct,
   879→          isOverloaded: utilizationPct > MAX_UTILIZATION,
   880→          isUnderutilized: utilizationPct < MIN_UTILIZATION,
   881→        });
   882→      }
   883→    }
   884→
   885→    return projections;
   886→  }
   887→
   888→  /**
   889→   * Calculate weekly capacity from configuration
   890→   */
   891→  private calculateWeeklyCapacity(
   892→    capacity: ManhourCapacity | null
   893→  ): { regular: number; overtime: number } {
   894→    if (!capacity) {
   895→      // Default capacity when not configured
   896→      return { regular: 200, overtime: 40 };
   897→    }
   898→
   899→    const dayHours = parseFloat(capacity.dayShiftHours ?? '0');
   900→    const nightHours = parseFloat(capacity.nightShiftHours ?? '0');
   901→    const weekendHours = parseFloat(capacity.weekendHours ?? '0');
   902→    const maxOvertimePct = parseFloat(capacity.maxOvertimePct ?? '20') / 100;
   903→
   904→    const regular = dayHours * 5 + nightHours * 5 + weekendHours * 2;
   905→    const overtime = regular * maxOvertimePct;
   906→
   907→    return { regular, overtime };
   908→  }
   909→
   910→  /**
   911→   * Get PM hours for a time period, separated into regular PM and overhaul
   912→   */
   913→  private async getPmHoursForPeriod(
   914→    depotId: string,
   915→    startDate: Date,
   916→    endDate: Date
   917→  ): Promise<{ pm: number; overhaul: number }> {
   918→    const startStr = format(startDate, 'yyyy-MM-dd');
   919→    const endStr = format(endDate, 'yyyy-MM-dd');
   920→
   921→    // Get scheduled PMs for the period
   922→    const scheduledPMs = await this.db
   923→      .select({
   924→        pmTypeId: pmSchedule.pmTypeId,
   925→        count: count(),
   926→      })
   927→      .from(pmSchedule)
   928→      .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
   929→      .where(
   930→        and(
   931→          eq(trains.currentDepotId, depotId),
   932→          gte(pmSchedule.targetDate, startStr),
   933→          lte(pmSchedule.targetDate, endStr),
   934→          eq(pmSchedule.status, 'SCHEDULED'),
   935→          isNull(pmSchedule.scenarioId) // Only real schedule, not scenarios
   936→        )
   937→      )
   938→      .groupBy(pmSchedule.pmTypeId);
   939→
   940→    if (scheduledPMs.length === 0) {
   941→      return { pm: 0, overhaul: 0 };
   942→    }
   943→
   944→    // Get estimated hours and track type for each PM type
   945→    const pmTypeIds = scheduledPMs.map((p) => p.pmTypeId);
   946→    const pmTypeDetails = await this.db.query.pmTypes.findMany({
   947→      where: inArray(pmTypes.id, pmTypeIds),
   948→      columns: { id: true, estimatedHours: true, trackType: true },
   949→    });
   950→
   951→    const detailsMap = new Map(
   952→      pmTypeDetails.map((pt) => [
   953→        pt.id,
   954→        {
   955→          hours: parseFloat(pt.estimatedHours ?? '0'),
   956→          isOverhaul: pt.trackType === 'OVERHAUL',
   957→        },
   958→      ])
   959→    );
   960→
   961→    // Calculate hours separated by type
   962→    let pmHours = 0;
   963→    let overhaulHours = 0;
   964→    for (const pm of scheduledPMs) {
   965→      const details = detailsMap.get(pm.pmTypeId);
   966→      if (!details) continue;
   967→      const hours = details.hours * pm.count;
   968→      if (details.isOverhaul) {
   969→        overhaulHours += hours;
   970→      } else {
   971→        pmHours += hours;
   972→      }
   973→    }
   974→
   975→    return { pm: pmHours, overhaul: overhaulHours };
   976→  }
