  1031→  // ===========================================================================
  1032→
  1033→  /**
  1034→   * Generate adjustments to level workload
  1035→   */
  1036→  private async generateAdjustments(
  1037→    projections: ProjectionData[]
  1038→  ): Promise<ProposedAdjustment[]> {
  1039→    const adjustments: ProposedAdjustment[] = [];
  1040→
  1041→    // Group projections by depot
  1042→    const byDepot = this.groupByDepot(projections);
  1043→
  1044→    for (const depotProjections of byDepot.values()) {
  1045→      const overloaded = depotProjections.filter((p) => p.isOverloaded);
  1046→      const underutilized = depotProjections.filter((p) => p.isUnderutilized);
  1047→
  1048→      // Track remaining capacity in underutilized weeks
  1049→      const underutilizedCapacity = new Map(
  1050→        underutilized.map((p) => [
  1051→          p.week.toISOString(),
  1052→          p.available.total - p.required.total,
  1053→        ])
  1054→      );
  1055→
  1056→      for (const overWeek of overloaded) {
  1057→        let remainingExcess = overWeek.required.total - overWeek.available.total;
  1058→
  1059→        // Try each strategy in priority order
  1060→        for (const strategy of LEVELING_STRATEGIES) {
  1061→          if (remainingExcess <= 0) break;
  1062→
  1063→          const adjustment = await this.tryStrategy(
  1064→            strategy,
  1065→            overWeek,
  1066→            underutilized,
  1067→            underutilizedCapacity,
  1068→            depotProjections,
  1069→            remainingExcess
  1070→          );
  1071→
  1072→          if (adjustment) {
  1073→            adjustments.push(adjustment);
  1074→            remainingExcess -= adjustment.hoursAdjusted;
  1075→
  1076→            // Update underutilized capacity if we used some
  1077→            if (
  1078→              adjustment.targetPeriod &&
  1079→              (adjustment.type === 'ADVANCE_PM' || adjustment.type === 'DEFER_PM')
  1080→            ) {
  1081→              const key = adjustment.targetPeriod.start.toISOString();
  1082→              const current = underutilizedCapacity.get(key) ?? 0;
  1083→              underutilizedCapacity.set(key, current - adjustment.hoursAdjusted);
  1084→            }
  1085→          }
  1086→        }
  1087→
  1088→        // If still overloaded, flag for manual review
  1089→        if (remainingExcess > 0) {
  1090→          adjustments.push({
  1091→            type: 'MANUAL_REVIEW',
  1092→            sourcePeriod: {
  1093→              start: overWeek.week,
  1094→              end: addDays(overWeek.week, 7),
  1095→            },
  1096→            hoursAdjusted: 0,
  1097→            affectedPMs: [],
  1098→            affectedTrains: [],
  1099→            costImpact: 0,
  1100→            riskLevel: 'HIGH',
  1101→            reason: `Unable to resolve ${remainingExcess.toFixed(0)}h overload - requires manual intervention`,
  1102→          });
  1103→        }
  1104→      }
  1105→    }
  1106→
  1107→    return adjustments;
  1108→  }
  1109→
  1110→  /**
  1111→   * Try a specific leveling strategy
  1112→   */
  1113→  private async tryStrategy(
  1114→    strategy: LevelingStrategy,
  1115→    overloadedWeek: ProjectionData,
  1116→    underutilizedWeeks: ProjectionData[],
  1117→    underutilizedCapacity: Map<string, number>,
  1118→    allProjections: ProjectionData[],
  1119→    excessHours: number
  1120→  ): Promise<ProposedAdjustment | null> {
  1121→    const maxHours = Math.min(strategy.maxHoursPerWeek, excessHours);
  1122→    const baseRate = await this.getBaseRate(overloadedWeek.depotId);
  1123→
  1124→    switch (strategy.type) {
  1125→      case 'ADVANCE_PM':
  1126→      case 'DEFER_PM':
  1127→        return this.tryShiftPmStrategy(
  1128→          strategy,
  1129→          overloadedWeek,
  1130→          underutilizedWeeks,
  1131→          underutilizedCapacity,
  1132→          maxHours,
  1133→          baseRate
  1134→        );
  1135→
  1136→      case 'ADD_OVERTIME':
  1137→        return this.tryOvertimeStrategy(strategy, overloadedWeek, maxHours, baseRate);
  1138→
  1139→      case 'CROSS_DEPOT':
  1140→        return this.tryCrossDepotStrategy(strategy, overloadedWeek, maxHours, baseRate);
  1141→
  1142→      case 'ADD_CONTRACTOR':
  1143→        return this.tryContractorStrategy(strategy, overloadedWeek, maxHours, baseRate);
  1144→
  1145→      default:
  1146→        return null;
  1147→    }
  1148→  }
  1149→
  1150→  /**
  1151→   * Try ADVANCE_PM or DEFER_PM strategy
  1152→   */
  1153→  private async tryShiftPmStrategy(
  1154→    strategy: LevelingStrategy,
  1155→    overloadedWeek: ProjectionData,
  1156→    underutilizedWeeks: ProjectionData[],
  1157→    underutilizedCapacity: Map<string, number>,
  1158→    maxHours: number,
  1159→    baseRate: number
  1160→  ): Promise<ProposedAdjustment | null> {
  1161→    const direction = strategy.type === 'ADVANCE_PM' ? -1 : 1;
  1162→
  1163→    // Find candidate weeks (before for ADVANCE, after for DEFER)
  1164→    const candidates = underutilizedWeeks
  1165→      .filter((w) => {
  1166→        const weekDiff = differenceInWeeks(w.week, overloadedWeek.week);
  1167→        const remainingCapacity = underutilizedCapacity.get(w.week.toISOString()) ?? 0;
  1168→        return (
  1169→          w.depotId === overloadedWeek.depotId &&
  1170→          weekDiff * direction > 0 &&
  1171→          Math.abs(weekDiff) <= 4 &&
  1172→          remainingCapacity > MIN_SHIFT_HOURS
  1173→        );
  1174→      })
  1175→      .sort(
  1176→        (a, b) =>
  1177→          Math.abs(differenceInWeeks(a.week, overloadedWeek.week)) -
  1178→          Math.abs(differenceInWeeks(b.week, overloadedWeek.week))
  1179→      );
  1180→
  1181→    for (const candidate of candidates) {
  1182→      const availableCapacity = underutilizedCapacity.get(candidate.week.toISOString()) ?? 0;
  1183→      const shiftHours = Math.min(maxHours, availableCapacity * 0.8);
  1184→
  1185→      if (shiftHours >= MIN_SHIFT_HOURS) {
  1186→        // Find PMs that can be shifted
  1187→        const shiftablePMs = await this.findShiftablePMs(
  1188→          overloadedWeek,
  1189→          candidate,
  1190→          shiftHours,
  1191→          strategy.type as 'ADVANCE_PM' | 'DEFER_PM'
  1192→        );
  1193→
  1194→        if (shiftablePMs.length > 0) {
  1195→          const actualHours = shiftablePMs.reduce((sum, pm) => sum + pm.estimatedHours, 0);
  1196→
  1197→          const weekNumSource = format(overloadedWeek.week, 'ww');
  1198→          const weekNumTarget = format(candidate.week, 'ww');
  1199→          const action = strategy.type === 'DEFER_PM' ? 'Defer' : 'Advance';
  1200→
  1201→          return {
  1202→            type: strategy.type,
  1203→            sourcePeriod: {
  1204→              start: overloadedWeek.week,
  1205→              end: addDays(overloadedWeek.week, 7),
  1206→            },
  1207→            targetPeriod: {
  1208→              start: candidate.week,
  1209→              end: addDays(candidate.week, 7),
  1210→            },
  1211→            hoursAdjusted: actualHours,
  1212→            affectedPMs: shiftablePMs.map((pm) => pm.id),
  1213→            affectedTrains: [...new Set(shiftablePMs.map((pm) => pm.trainId))],
  1214→            costImpact: actualHours * baseRate * (strategy.costMultiplier - 1),
  1215→            riskLevel: strategy.riskLevel,
  1216→            reason: `${action} ${actualHours.toFixed(0)}h (${shiftablePMs.length} PMs) from Week ${weekNumSource} to Week ${weekNumTarget}`,
  1217→          };
  1218→        }
  1219→      }
  1220→    }
  1221→
  1222→    return null;
  1223→  }
  1224→
  1225→  /**
  1226→   * Try ADD_OVERTIME strategy
  1227→   */
  1228→  private tryOvertimeStrategy(
  1229→    strategy: LevelingStrategy,
  1230→    overloadedWeek: ProjectionData,
  1231→    maxHours: number,
  1232→    baseRate: number
  1233→  ): ProposedAdjustment | null {
  1234→    const availableOvertime = overloadedWeek.available.overtime;
  1235→    const overtimeHours = Math.min(maxHours, availableOvertime);
  1236→
  1237→    if (overtimeHours >= MIN_OVERTIME_HOURS) {
  1238→      const weekNum = format(overloadedWeek.week, 'ww');
  1239→
  1240→      return {
  1241→        type: 'ADD_OVERTIME',
  1242→        sourcePeriod: {
  1243→          start: overloadedWeek.week,
  1244→          end: addDays(overloadedWeek.week, 7),
  1245→        },
  1246→        targetPeriod: {
  1247→          start: overloadedWeek.week,
  1248→          end: addDays(overloadedWeek.week, 7),
  1249→        },
  1250→        hoursAdjusted: overtimeHours,
  1251→        affectedPMs: [],
  1252→        affectedTrains: [],
  1253→        costImpact: overtimeHours * baseRate * (strategy.costMultiplier - 1),
  1254→        riskLevel: strategy.riskLevel,
  1255→        reason: `Add ${overtimeHours.toFixed(0)}h overtime in Week ${weekNum}`,
  1256→      };
  1257→    }
  1258→
  1259→    return null;
  1260→  }
  1261→
  1262→  /**
  1263→   * Try CROSS_DEPOT strategy
  1264→   */
  1265→  private async tryCrossDepotStrategy(
  1266→    strategy: LevelingStrategy,
  1267→    overloadedWeek: ProjectionData,
  1268→    maxHours: number,
  1269→    baseRate: number
  1270→  ): Promise<ProposedAdjustment | null> {
  1271→    const otherDepots = await this.findDepotsWithCapacity(
  1272→      overloadedWeek.week,
  1273→      maxHours,
  1274→      overloadedWeek.depotId
  1275→    );
  1276→
  1277→    if (otherDepots.length > 0) {
  1278→      const best = otherDepots[0];
  1279→      const weekNum = format(overloadedWeek.week, 'ww');
  1280→
  1281→      return {
  1282→        type: 'CROSS_DEPOT',
  1283→        sourcePeriod: {
  1284→          start: overloadedWeek.week,
  1285→          end: addDays(overloadedWeek.week, 7),
  1286→        },
  1287→        targetPeriod: {
  1288→          start: overloadedWeek.week,
  1289→          end: addDays(overloadedWeek.week, 7),
  1290→        },
  1291→        hoursAdjusted: best.availableHours,
  1292→        affectedPMs: [],
  1293→        affectedTrains: [],
  1294→        costImpact: best.availableHours * baseRate * (strategy.costMultiplier - 1),
  1295→        riskLevel: strategy.riskLevel,
  1296→        reason: `Request ${best.availableHours.toFixed(0)}h support from ${best.depotName} in Week ${weekNum}`,
  1297→      };
  1298→    }
  1299→
  1300→    return null;
  1301→  }
  1302→
  1303→  /**
  1304→   * Try ADD_CONTRACTOR strategy
  1305→   */
  1306→  private tryContractorStrategy(
  1307→    strategy: LevelingStrategy,
  1308→    overloadedWeek: ProjectionData,
  1309→    maxHours: number,
  1310→    baseRate: number
  1311→  ): ProposedAdjustment {
  1312→    const weekNum = format(overloadedWeek.week, 'ww');
  1313→
  1314→    return {
  1315→      type: 'ADD_CONTRACTOR',
  1316→      sourcePeriod: {
  1317→        start: overloadedWeek.week,
  1318→        end: addDays(overloadedWeek.week, 7),
  1319→      },
  1320→      targetPeriod: {
  1321→        start: overloadedWeek.week,
  1322→        end: addDays(overloadedWeek.week, 7),
  1323→      },
  1324→      hoursAdjusted: maxHours,
  1325→      affectedPMs: [],
  1326→      affectedTrains: [],
  1327→      costImpact: maxHours * baseRate * (strategy.costMultiplier - 1),
  1328→      riskLevel: strategy.riskLevel,
  1329→      reason: `Engage contractor for ${maxHours.toFixed(0)}h in Week ${weekNum}`,
  1330→    };
  1331→  }
  1332→
  1333→  /**
  1334→   * Find PMs that can be shifted to another week
  1335→   */
  1336→  private async findShiftablePMs(
  1337→    fromWeek: ProjectionData,
  1338→    toWeek: ProjectionData,
  1339→    targetHours: number,
  1340→    strategy: 'ADVANCE_PM' | 'DEFER_PM'
  1341→  ): Promise<ShiftablePM[]> {
  1342→    const fromStart = format(fromWeek.week, 'yyyy-MM-dd');
  1343→    const fromEnd = format(addDays(fromWeek.week, 6), 'yyyy-MM-dd');
  1344→
  1345→    // Get PMs in the overloaded week
  1346→    const scheduledPMs = await this.db
  1347→      .select({
  1348→        id: pmSchedule.id,
  1349→        trainId: pmSchedule.trainId,
  1350→        pmTypeId: pmSchedule.pmTypeId,
  1351→        targetDate: pmSchedule.targetDate,
  1352→        constraintStart: pmSchedule.constraintStart,
  1353→        constraintEnd: pmSchedule.constraintEnd,
  1354→        isLocked: pmSchedule.isLocked,
  1355→      })
  1356→      .from(pmSchedule)
  1357→      .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
  1358→      .where(
  1359→        and(
  1360→          eq(trains.currentDepotId, fromWeek.depotId),
  1361→          gte(pmSchedule.targetDate, fromStart),
  1362→          lte(pmSchedule.targetDate, fromEnd),
  1363→          inArray(pmSchedule.status, ['SCHEDULED']), // Not CONFIRMED, IN_PROGRESS, or COMPLETED
  1364→          eq(pmSchedule.isLocked, false), // Not locked
  1365→          isNull(pmSchedule.scenarioId) // Real schedule
  1366→        )
  1367→      );
  1368→
  1369→    if (scheduledPMs.length === 0) {
  1370→      return [];
  1371→    }
  1372→
  1373→    // Get PM type info
  1374→    const pmTypeIds = [...new Set(scheduledPMs.map((p) => p.pmTypeId))];
  1375→    const pmTypeInfo = await this.db.query.pmTypes.findMany({
  1376→      where: inArray(pmTypes.id, pmTypeIds),
  1377→      columns: { id: true, pmCode: true, estimatedHours: true },
  1378→    });
  1379→    const typeMap = new Map(pmTypeInfo.map((pt) => [pt.id, pt]));
  1380→
  1381→    // Filter PMs that can be shifted to target week
  1382→    const shiftablePMs: ShiftablePM[] = [];
  1383→    let accumulatedHours = 0;
  1384→
  1385→    for (const pm of scheduledPMs) {
  1386→      if (accumulatedHours >= targetHours) break;
  1387→
  1388→      const pmType = typeMap.get(pm.pmTypeId);
  1389→      if (!pmType) continue;
  1390→
  1391→      const constraintStart = pm.constraintStart ? parseISO(pm.constraintStart) : null;
  1392→      const constraintEnd = pm.constraintEnd ? parseISO(pm.constraintEnd) : null;
  1393→
  1394→      // Check if target week is within compliance window
  1395→      const targetDate = strategy === 'ADVANCE_PM' ? toWeek.week : addDays(toWeek.week, 6);
  1396→
  1397→      const withinWindow =
  1398→        (!constraintStart || !isBefore(targetDate, constraintStart)) &&
  1399→        (!constraintEnd || !isAfter(targetDate, constraintEnd));
  1400→
  1401→      if (withinWindow) {
  1402→        const hours = parseFloat(pmType.estimatedHours ?? '0');
  1403→        shiftablePMs.push({
  1404→          id: pm.id,
  1405→          trainId: pm.trainId,
  1406→          pmTypeCode: pmType.pmCode,
  1407→          estimatedHours: hours,
  1408→          currentDate: parseISO(pm.targetDate),
  1409→          constraintStart: constraintStart ?? new Date(0),
  1410→          constraintEnd: constraintEnd ?? new Date(9999, 11, 31),
  1411→        });
  1412→        accumulatedHours += hours;
  1413→      }
  1414→    }
  1415→
  1416→    return shiftablePMs;
  1417→  }
  1418→
  1419→  /**
  1420→   * Find other depots with available capacity
  1421→   */
  1422→  private async findDepotsWithCapacity(
  1423→    week: Date,
  1424→    minHours: number,
  1425→    excludeDepotId: string
  1426→  ): Promise<DepotWithCapacity[]> {
  1427→    // Get all depots except the excluded one
  1428→    const otherDepots = await this.db.query.depots.findMany({
  1429→      where: sql`${depots.id} != ${excludeDepotId}`,
  1430→    });
  1431→
  1432→    const results: DepotWithCapacity[] = [];
  1433→
  1434→    for (const depot of otherDepots) {
  1435→      const capacity = await this.getCapacity(depot.id, week);
  1436→      if (!capacity) continue;
  1437→
  1438→      // Get PM hours for this depot/week (PM + overhaul)
  1439→      const pmResult = await this.getPmHoursForPeriod(depot.id, week, addDays(week, 6));
  1440→      const totalPmHours = pmResult.pm + pmResult.overhaul;
  1441→
  1442→      // Calculate available capacity
  1443→      const weeklyCapacity = this.calculateWeeklyCapacity(capacity);
  1444→      const availableHours = weeklyCapacity.regular + weeklyCapacity.overtime - totalPmHours;
  1445→
  1446→      if (availableHours >= minHours) {
  1447→        results.push({
  1448→          depotId: depot.id,
  1449→          depotCode: depot.code,
  1450→          depotName: depot.name,
  1451→          availableHours: Math.min(availableHours, minHours),
  1452→        });
  1453→      }
  1454→    }
  1455→
  1456→    // Sort by available hours (descending)
  1457→    return results.sort((a, b) => b.availableHours - a.availableHours);
  1458→  }
  1459→
  1460→  /**
  1461→   * Get base labor rate for a depot
  1462→   */
  1463→  private async getBaseRate(depotId?: string): Promise<number> {
  1464→    if (!depotId) {
  1465→      return DEFAULT_BASE_RATE;
  1466→    }
  1467→
  1468→    const rate = await this.db.query.laborRates.findFirst({
  1469→      where: and(
  1470→        eq(laborRates.depotId, depotId),
  1471→        lte(laborRates.effectiveFrom, format(new Date(), 'yyyy-MM-dd')),
  1472→        or(isNull(laborRates.effectiveTo), gte(laborRates.effectiveTo, format(new Date(), 'yyyy-MM-dd')))
  1473→      ),
  1474→      orderBy: [desc(laborRates.effectiveFrom)],
  1475→    });
  1476→
  1477→    return rate ? parseFloat(rate.regularHourlyRate ?? String(DEFAULT_BASE_RATE)) : DEFAULT_BASE_RATE;
  1478→  }
  1479→
  1480→  // ===========================================================================
  1481→  // Private: Apply Adjustments & Calculate Metrics
  1482→  // ===========================================================================
  1483→
  1484→  /**
  1485→   * Apply adjustments to projections (simulation, not persisted)
  1486→   */
  1487→  private applyAdjustments(
  1488→    projections: ProjectionData[],
  1489→    adjustments: ProposedAdjustment[]
  1490→  ): ProjectionData[] {
  1491→    // Create deep copy
  1492→    const leveled = projections.map((p) => ({
  1493→      ...p,
  1494→      required: { ...p.required },
  1495→      available: { ...p.available },
  1496→    }));
  1497→
  1498→    // Build lookup by week
  1499→    const weekMap = new Map(leveled.map((p) => [p.week.toISOString(), p]));
  1500→
  1501→    for (const adj of adjustments) {
  1502→      if (adj.type === 'MANUAL_REVIEW') continue;
  1503→
  1504→      const sourceKey = adj.sourcePeriod.start.toISOString();
  1505→      const source = weekMap.get(sourceKey);
  1506→
  1507→      if (adj.type === 'ADVANCE_PM' || adj.type === 'DEFER_PM') {
  1508→        // Move hours from source to target
  1509→        if (source && adj.targetPeriod) {
  1510→          const targetKey = adj.targetPeriod.start.toISOString();
  1511→          const target = weekMap.get(targetKey);
  1512→
  1513→          if (target) {
  1514→            source.required.pm -= adj.hoursAdjusted;
  1515→            source.required.total -= adj.hoursAdjusted;
  1516→            target.required.pm += adj.hoursAdjusted;
  1517→            target.required.total += adj.hoursAdjusted;
  1518→          }
  1519→        }
  1520→      } else if (adj.type === 'ADD_OVERTIME') {
  1521→        // Increase available hours in source
  1522→        if (source) {
  1523→          // Overtime is already counted in available.total
  1524→          // No change needed to projected available hours
  1525→        }
  1526→      } else if (adj.type === 'CROSS_DEPOT' || adj.type === 'ADD_CONTRACTOR') {
  1527→        // Reduce required hours in source (work transferred out)
  1528→        if (source) {
  1529→          source.required.total -= adj.hoursAdjusted;
  1530→        }
  1531→      }
  1532→    }
  1533→
  1534→    // Recalculate metrics for all weeks
  1535→    for (const p of leveled) {
  1536→      p.variance = p.available.total - p.required.total;
  1537→      p.utilizationPct = p.available.total > 0 ? p.required.total / p.available.total : 0;
  1538→      p.isOverloaded = p.utilizationPct > MAX_UTILIZATION;
  1539→      p.isUnderutilized = p.utilizationPct < MIN_UTILIZATION;
  1540→    }
  1541→
  1542→    return leveled;
  1543→  }
  1544→
  1545→  /**
  1546→   * Calculate aggregate metrics
  1547→   */
  1548→  private calculateMetrics(projections: ProjectionData[]): LevelingMetrics {
  1549→    if (projections.length === 0) {
  1550→      return {
  1551→        avgUtilization: 0,
  1552→        minUtilization: 0,
  1553→        maxUtilization: 0,
  1554→        overloadedWeeks: 0,
  1555→        underutilizedWeeks: 0,
  1556→        totalRequiredHours: 0,
  1557→        totalAvailableHours: 0,
  1558→      };
  1559→    }
  1560→
  1561→    const utilizations = projections.map((p) => p.utilizationPct);
  1562→
  1563→    return {
  1564→      avgUtilization: utilizations.reduce((a, b) => a + b, 0) / utilizations.length,
  1565→      minUtilization: Math.min(...utilizations),
  1566→      maxUtilization: Math.max(...utilizations),
  1567→      overloadedWeeks: projections.filter((p) => p.isOverloaded).length,
  1568→      underutilizedWeeks: projections.filter((p) => p.isUnderutilized).length,
  1569→      totalRequiredHours: projections.reduce((sum, p) => sum + p.required.total, 0),
  1570→      totalAvailableHours: projections.reduce((sum, p) => sum + p.available.total, 0),
  1571→    };
  1572→  }
  1573→
  1574→  /**
  1575→   * Group projections by depot
  1576→   */
  1577→  private groupByDepot(projections: ProjectionData[]): Map<string, ProjectionData[]> {
  1578→    const result = new Map<string, ProjectionData[]>();
  1579→
  1580→    for (const p of projections) {
  1581→      const existing = result.get(p.depotId) ?? [];
  1582→      existing.push(p);
  1583→      result.set(p.depotId, existing);
  1584→    }
  1585→
  1586→    return result;
  1587→  }
  1588→
  1589→  // ===========================================================================
  1590→  // Private: Persistence
  1591→  // ===========================================================================
  1592→
  1593→  /**
  1594→   * Persist projections and adjustments to database
  1595→   */
  1596→  private async persistProjections(
  1597→    runId: string,
  1598→    projections: ProjectionData[],
  1599→    adjustments: ProposedAdjustment[]
  1600→  ): Promise<void> {
  1601→    await this.inTransaction('persistProjections', async (tx, span) => {
  1602→      span.setAttribute('projectionRunId', runId);
  1603→      span.setAttribute('projectionCount', projections.length);
  1604→      span.setAttribute('adjustmentCount', adjustments.length);
  1605→
  1606→      // Insert projections
  1607→      for (const p of projections) {
  1608→        const [inserted] = await tx
  1609→          .insert(manhourProjections)
  1610→          .values({
  1611→            projectionRunId: runId,
  1612→            depotId: p.depotId,
  1613→            periodStart: format(p.week, 'yyyy-MM-dd'),
  1614→            periodEnd: format(addDays(p.week, 6), 'yyyy-MM-dd'),
  1615→            granularity: p.granularity,
  1616→            requiredPmHours: String(p.required.pm),
  1617→            requiredCorrectiveHours: String(p.required.corrective),
  1618→            requiredOverhaulHours: String(p.required.overhaul),
  1619→            requiredTotalHours: String(p.required.total),
  1620→            availableRegularHours: String(p.available.regular),
  1621→            availableOvertimeHours: String(p.available.overtime),
  1622→            availableTotalHours: String(p.available.total),
  1623→          })
  1624→          .returning();
  1625→
  1626→        // Insert adjustments for this projection
  1627→        const projectionAdjustments = adjustments.filter(
  1628→          (a) =>
  1629→            a.sourcePeriod.start.toISOString() === p.week.toISOString() &&
  1630→            (!p.depotCode || a.sourcePeriod.start.toISOString() === p.week.toISOString())
  1631→        );
  1632→
  1633→        for (const adj of projectionAdjustments) {
  1634→          await tx.insert(manhourAdjustments).values({
  1635→            projectionId: inserted.id,
  1636→            adjustmentType: adj.type,
  1637→            sourcePeriodStart: format(adj.sourcePeriod.start, 'yyyy-MM-dd'),
  1638→            sourcePeriodEnd: format(adj.sourcePeriod.end, 'yyyy-MM-dd'),
  1639→            targetPeriodStart: adj.targetPeriod
  1640→              ? format(adj.targetPeriod.start, 'yyyy-MM-dd')
  1641→              : null,
  1642→            targetPeriodEnd: adj.targetPeriod ? format(adj.targetPeriod.end, 'yyyy-MM-dd') : null,
  1643→            hoursAdjusted: String(adj.hoursAdjusted),
  1644→            affectedPmIds: adj.affectedPMs,
  1645→            affectedTrainIds: adj.affectedTrains,
  1646→            costImpact: String(adj.costImpact),
  1647→            riskImpact: adj.riskLevel,
  1648→            reason: adj.reason,
  1649→            status: 'PROPOSED',
  1650→          });
  1651→        }
  1652→      }
  1653→    });
  1654→  }
  1655→}
