    43→
    44→describe('ManHourLevelingService', () => {
    45→  describe('Initialization', () => {
    46→    test('should create a ManHourLevelingService instance', () => {
    47→      const service = new ManHourLevelingService();
    48→      expect(service).toBeDefined();
    49→      expect(service).toBeInstanceOf(ManHourLevelingService);
    50→    });
    51→
