    58→
    59→  describe('Leveling Strategies', () => {
    60→    test('should have 5 strategies in priority order', () => {
    61→      expect(LEVELING_STRATEGIES).toHaveLength(5);
    62→    });
    63→
    64→    test('should have ADVANCE_PM as priority 1', () => {
    65→      const advancePm = LEVELING_STRATEGIES.find((s) => s.type === 'ADVANCE_PM');
