    90→
    91→    test('should have CROSS_DEPOT as priority 4', () => {
    92→      const crossDepot = LEVELING_STRATEGIES.find((s) => s.type === 'CROSS_DEPOT');
    93→      expect(crossDepot).toBeDefined();
    94→      expect(crossDepot?.priority).toBe(4);
