/**
 * MMS Man-hour Leveling Service Unit Tests
 *
 * Tests for the Man-hour Leveling Service covering:
 * - Service initialization and singleton pattern
 * - Type definitions and interfaces
 * - Leveling strategy configurations
 * - Utilization targets and thresholds
 * - Imbalance detection logic
 * - Adjustment generation algorithms
 * - Metrics calculation
 *
 * Note: These tests use Bun's test framework and document expected behavior.
 * Integration tests with actual database should be in a separate test suite.
 *
 * @see src/services/man-hour-leveling.ts
 * @see specs/004-domain-services.md Section 4.6
 */

import { describe, test, expect } from 'bun:test';
import {
  ManHourLevelingService,
  getManHourLevelingService,
  LEVELING_STRATEGIES,
  type AdjustmentType,
  type RiskLevel,
  type AdjustmentStatus,
  type LevelingStrategy,
  type LevelingTimePeriod,
  type RequiredHours,
  type AvailableHours,
  type ProjectionData,
  type ProposedAdjustment,
  type LevelingMetrics,
  type LevelingImprovement,
  type LaborCapacityResult,
  type LevelingResult,
  type GenerateProjectionsRequest,
  type UpdateCapacityRequest,
  type ProjectionFilters,
  type AdjustmentFilters,
} from './man-hour-leveling';

describe('ManHourLevelingService', () => {
  describe('Initialization', () => {
    test('should create a ManHourLevelingService instance', () => {
      const service = new ManHourLevelingService();
      expect(service).toBeDefined();
      expect(service).toBeInstanceOf(ManHourLevelingService);
    });

    test('should return singleton instance via getManHourLevelingService', () => {
      const instance1 = getManHourLevelingService();
      const instance2 = getManHourLevelingService();
      expect(instance1).toBe(instance2);
    });
  });

  describe('Leveling Strategies', () => {
    test('should have 5 strategies in priority order', () => {
      expect(LEVELING_STRATEGIES).toHaveLength(5);
    });

    test('should have ADVANCE_PM as priority 1', () => {
      const advancePm = LEVELING_STRATEGIES.find((s) => s.type === 'ADVANCE_PM');
      expect(advancePm).toBeDefined();
      expect(advancePm?.priority).toBe(1);
      expect(advancePm?.costMultiplier).toBe(1.1);
      expect(advancePm?.riskLevel).toBe('LOW');
      expect(advancePm?.maxHoursPerWeek).toBe(40);
    });

    test('should have DEFER_PM as priority 2', () => {
      const deferPm = LEVELING_STRATEGIES.find((s) => s.type === 'DEFER_PM');
      expect(deferPm).toBeDefined();
      expect(deferPm?.priority).toBe(2);
      expect(deferPm?.costMultiplier).toBe(1.05);
      expect(deferPm?.riskLevel).toBe('LOW');
      expect(deferPm?.maxHoursPerWeek).toBe(40);
    });

    test('should have ADD_OVERTIME as priority 3', () => {
      const overtime = LEVELING_STRATEGIES.find((s) => s.type === 'ADD_OVERTIME');
      expect(overtime).toBeDefined();
      expect(overtime?.priority).toBe(3);
      expect(overtime?.costMultiplier).toBe(1.5);
      expect(overtime?.riskLevel).toBe('NONE');
      expect(overtime?.maxHoursPerWeek).toBe(80);
    });

    test('should have CROSS_DEPOT as priority 4', () => {
      const crossDepot = LEVELING_STRATEGIES.find((s) => s.type === 'CROSS_DEPOT');
      expect(crossDepot).toBeDefined();
      expect(crossDepot?.priority).toBe(4);
      expect(crossDepot?.costMultiplier).toBe(1.3);
      expect(crossDepot?.riskLevel).toBe('MEDIUM');
      expect(crossDepot?.maxHoursPerWeek).toBe(60);
    });

